	return "unknown"
}

func hostname(deps TrustDeps) string {
	if deps.Hostname != "" {
		return deps.Hostname
	}
	if h, err := os.Hostname(); err == nil {
		return h
	}
	return "unknown"
}

func outWriter(deps TrustDeps, cmd *cobra.Command) io.Writer {
	if deps.Out != nil {
