	t.Parallel()

	cmd := NewTrustCommand(TrustDeps{})
	want := []string{
		"status", "pending", "diff", "promote", "pin", "verify",
		"reset", "add", "revoke", "allow-new-shas", "compact",
	}
	got := make(map[string]bool)
	for _, c := range cmd.Commands() {
		got[c.Name()] = true
	}
