	}
	index := make(map[string]Case, len(all))
	for _, tc := range all {
		index[tc.Name] = tc
	}
	out := make([]Case, 0, len(names))
	for _, name := range names {
		tc, ok := index[name]
		if !ok {
			t.Fatalf("missing corpus case %q", name)
		}
		out = append(out, tc)
	}
