	if err != nil {
		return fmt.Errorf("contract: ID non-integer number %q: %w", string(trimmed), err)
	}
	id.kind = idKindInt
	id.i = v
	id.s = ""
	return nil
}

// Request is a JSON-RPC 2.0 request: an ID, a method, and optional
// params. Carries the reserved _meta field per the aienvs/v1 contract.
type Request struct {
